navigator.serviceWorker.ready.then(registration => {
  return registration.sync.register('post-message');
});

// In service worker:
self.addEventListener('sync', event => {
  if (event.tag === 'post-message') {
    event.waitUntil(sendPendingMessages());
  }
});
